const BAR_LABEL = { DL: "bar on left", DR: "bar on right", DF: "bar on front" };
const L4E_LABEL = { DF: "L4E", DR: "ML4E-R", DL: "ML4E-L" };
const openOfEkey = (ek) => {
  const p = ek.split(",");
  if (p[3] !== "30") return "DF";
  if (p[5] !== "50") return "DR";
  if (p[4] !== "40") return "DL";
  return "";
};
const barOfEkey = (ek) => {
  const p = ek.split(",");
  if (p[4] === "40") return "DL";
  if (p[5] === "50") return "DR";
  if (p[3] === "30") return "DF";
  return "";
};
const lookupName = (render, uTwist, caseKey) => {
  // exact angle first, then the AUF-rotations of the same real case, then class label
  const t = copyState(render);
  for (let k = 0; k < 3; k++) {
    const nm = SHEET.NAME[stateKey(t) + "|" + ((uTwist + k) % 3)];
    if (nm) return nm;
    applyMove(t, "U", false);
  }
  return SHEET.CNAME[caseKey] || null;
};
function algGroups(render, uTwist) {
  const groups = [];
  const collect = (label, st, tw) => {
    const exact = SHEET.ALG[stateKey(st) + "|" + tw] || [];
    if (exact.length) groups.push({ label, exact });
  };
  collect("This angle", render, uTwist);
  const u = copyState(render); applyMove(u, "U", false);
  collect("Do U first, then", u, (uTwist + 1) % 3);
  const up = copyState(render); applyMove(up, "U", true);
  collect("Do U' first, then", up, (uTwist + 2) % 3);
  return groups;
}

function AlgList({ exact }) {
  return (
    <div className="alglist">
      {exact.map(([a, nm], i) => (
        <div key={"e" + i} className="algrow">
          <span className="mono alg">{a}</span>
          {nm ? <span className="algname">{nm}</span> : null}
        </div>
      ))}
    </div>
  );
}

function AlgPanel({ panel, onClose }) {
  const set = SET_BY_ID[panel.set];
  let title, body;
  if (panel.kind === "live") {
    title = lookupName(panel.render, panel.uTwist, panel.caseKey) || "Unnamed case";
    const groups = algGroups(panel.render, panel.uTwist);
    body = (
      <>
        <div className="panelimg"><PyraminxNet state={panel.render} uTwist={panel.uTwist} /></div>
        {groups.length === 0 ? (
          <div className="empty">No algs in the sheet for this state yet.</div>
        ) : groups.map((g, i) => (
          <div key={i} className="alggroup">
            <div className="grouphead">{g.label}</div>
            <AlgList exact={g.exact} />
          </div>
        ))}
      </>
    );
  } else {
    title = SHEET.CNAME[panel.caseKey] || "Unnamed case";
    const pres = SHEET.PRES[panel.caseKey] || [];
    body = pres.length === 0 ? (
      <div className="empty">No sheet entries for this case yet.</div>
    ) : pres.map(([ek, tw, nm], i) => (
      <div key={i} className="alggroup presrow">
        <div className="panelimg small"><PyraminxNet state={keyToState(ek)} uTwist={tw} /></div>
        <div className="presbody">
          <div className="grouphead">{nm} <span className="bartag">{panel.set === "l4e" ? (L4E_LABEL[openOfEkey(ek)] || "") : (BAR_LABEL[barOfEkey(ek)] || "")}</span></div>
          <AlgList exact={SHEET.ALG[ek + "|" + tw] || []} />
        </div>
      </div>
    ));
  }
  return (
    <div className="overlay" onPointerDown={(e) => { if (e.target === e.currentTarget) onClose(); }}>
      <div className="modal">
        <div className="modalhead">
          <div>
            <div className="modaltitle">{title}</div>
            <span className="tag" style={{ "--cdot": set.color }}><span className="dot" />{set.name}</span>
          </div>
          <button className="closebtn" onClick={onClose}>{"\u00d7"}</button>
        </div>
        {body}
      </div>
    </div>
  );
}

function BarTriangle({ bar, onPick }) {
  const P = { B: [50, 12], L: [12, 78], R: [88, 78] };
  const edges = [
    { id: "DF", a: P.L, b: P.R },
    { id: "DL", a: P.L, b: P.B },
    { id: "DR", a: P.R, b: P.B },
  ];
  return (
    <svg viewBox="0 0 100 90" className="bar-tri" aria-label="presolved edge">
      <polygon points="50,12 12,78 88,78" className="tri-fill" />
      {edges.map((ed) => (
        <line key={ed.id} x1={ed.a[0]} y1={ed.a[1]} x2={ed.b[0]} y2={ed.b[1]}
          className={"tri-edge" + (bar === ed.id ? " sel" : "")} onClick={() => onPick(ed.id)} />
      ))}
      <text x="50" y="58" className="tri-label">{bar}</text>
    </svg>
  );
}

export default function L5ETrainer() {
  const distRef = useRef(null);
  const poolsRef = useRef(null);
  const [ready, setReady] = useState(false);

  const [bar, setBar] = useState("DL");
  const [selected, setSelected] = useState(() => new Set(L5E_IDS));
  const [mode, setMode] = useState("drill");
  const [settingsOpen, setSettingsOpen] = useState(false);

  const [current, setCurrent] = useState(null); // {scramble, set, caseKey, render, uTwist}
  const [phase, setPhase] = useState("ready");
  const [elapsed, setElapsed] = useState(0);
  const [last, setLast] = useState(null);
  const [caseStats, setCaseStats] = useState({});
  const [session, setSession] = useState([]);
  const [recap, setRecap] = useState(null);
  const [expandedSet, setExpandedSet] = useState(null);
  const [panel, setPanel] = useState(null);

  const t0 = useRef(0);
  const raf = useRef(0);
  const stoppedAt = useRef(0);
  const loadedStore = useRef(false);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const res = await window.storage.get(STORE_KEY);
        if (res && res.value && !cancelled) {
          const d = JSON.parse(res.value);
          if (d.caseStats) {
            const migrated = {};
            for (const [ck, st] of Object.entries(d.caseStats)) {
              if (!ck.includes("|")) continue; // legacy edges-only stats predate twist-distinct cases
              migrated[ck] = st.set === "ml4e" ? { ...st, set: "l4e" } : st;
            }
            setCaseStats(migrated);
          }
          if (d.bar) setBar(d.bar);
          if (Array.isArray(d.selected)) setSelected(new Set(d.selected.filter((id) => SET_BY_ID[id])));
        }
      } catch (e) { /* first run */ }
      loadedStore.current = true;
      setTimeout(() => {
        if (cancelled) return;
        distRef.current = buildDist();
        poolsRef.current = buildPools();
        setReady(true);
      }, 40);
    })();
    return () => { cancelled = true; };
  }, []);

  const saveTimer = useRef(0);
  useEffect(() => {
    if (!loadedStore.current) return;
    clearTimeout(saveTimer.current);
    saveTimer.current = setTimeout(() => {
      try {
        window.storage.set(STORE_KEY, JSON.stringify({ caseStats, bar, selected: [...selected] })).catch(() => {});
      } catch (e) {}
    }, 400);
  }, [caseStats, bar, selected]);

  const makeScramble = useCallback((setId, caseKey, presArr) => {
    let physical = null, scramble = null, uTwist = 0, target = 0;
    for (let attempt = 0; attempt < 30; attempt++) {
      const pres = presArr[Math.floor(Math.random() * presArr.length)];
      physical = setId === "l4e" ? copyState(pres.st) : rotateFrame(copyState(pres.st), BAR_ROT[bar]);
      target = pres.t;
      scramble = maskedScramble(physical, distRef.current);
      if (!scramble) continue;
      uTwist = 0;
      for (const t of scramble.split(" ")) {
        if (t[0] === "U") uTwist = (uTwist + (t.includes("'") ? 2 : 1)) % 3;
      }
      if (uTwist === target) break;
    }
    // if the generator could not hit the target twist, report the case actually shown
    const ck = scramble && uTwist === target ? caseKey : realCanonKey(physical, uTwist);
    return { scramble, set: setId, caseKey: ck, render: physical, uTwist };
  }, [bar]);

  const poolOf = useCallback((id) => {
    const pools = poolsRef.current;
    return id === "l4e" ? pools["l4e-" + bar] : pools[id];
  }, [bar]);

  const nextDrill = useCallback(() => {
    const ids = [...selected].filter((id) => poolOf(id));
    if (!ids.length) { setCurrent(null); return; }
    const total = ids.reduce((a, id) => a + poolOf(id).states.length, 0);
    let r = Math.floor(Math.random() * total);
    for (const id of ids) {
      const n = poolOf(id).states.length;
      if (r < n) {
        const pick = poolOf(id).states[r];
        setCurrent(makeScramble(id, pick.caseKey, poolOf(id).classes.get(pick.caseKey)));
        return;
      }
      r -= n;
    }
  }, [selected, makeScramble, poolOf]);

  const startRecap = useCallback(() => {
    const q = [];
    for (const id of [...selected]) {
      if (!poolOf(id)) continue;
      for (const ck of poolOf(id).classes.keys()) q.push({ set: id, caseKey: ck });
    }
    const queue = shuffled(q);
    setRecap({ queue, idx: 0 });
    if (queue.length) {
      const it = queue[0];
      setCurrent(makeScramble(it.set, it.caseKey, poolOf(it.set).classes.get(it.caseKey)));
    } else setCurrent(null);
  }, [selected, makeScramble, poolOf]);

  const advance = useCallback(() => {
    if (mode === "drill") { nextDrill(); return; }
    setRecap((r) => {
      if (!r) return r;
      const idx = r.idx + 1;
      if (idx >= r.queue.length) { setCurrent(null); return { ...r, idx }; }
      const it = r.queue[idx];
      setCurrent(makeScramble(it.set, it.caseKey, poolOf(it.set).classes.get(it.caseKey)));
      return { ...r, idx };
    });
  }, [mode, nextDrill, makeScramble, poolOf]);

  useEffect(() => {
    if (!ready) return;
    setPhase("ready");
    setLast(null);
    if (mode === "drill") nextDrill();
    else startRecap();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [ready, bar, selected, mode]);

  const tick = useCallback(() => {
    setElapsed(performance.now() - t0.current);
    raf.current = requestAnimationFrame(tick);
  }, []);
  const startTimer = useCallback(() => {
    if (!current || !current.scramble) return;
    t0.current = performance.now();
    setElapsed(0);
    setPhase("running");
    raf.current = requestAnimationFrame(tick);
  }, [current, tick]);
  const stopTimer = useCallback(() => {
    cancelAnimationFrame(raf.current);
    const ms = performance.now() - t0.current;
    stoppedAt.current = performance.now();
    setElapsed(ms);
    setPhase("stopped");
    if (current) {
      const rec = { ms, set: current.set, caseKey: current.caseKey, render: current.render, uTwist: current.uTwist };
      setLast(rec);
      setSession((s) => [...s.slice(-49), rec]);
      setCaseStats((cs) => {
        const prev = cs[current.caseKey] || { n: 0, best: Infinity, sum: 0, set: current.set };
        return { ...cs, [current.caseKey]: { set: current.set, n: prev.n + 1, best: Math.min(prev.best, ms), sum: prev.sum + ms } };
      });
    }
    advance();
  }, [current, advance]);

  const trigger = useCallback(() => {
    if (!ready) return;
    if (phase === "running") { stopTimer(); return; }
    if (performance.now() - stoppedAt.current < 350) return;
    startTimer();
  }, [ready, phase, startTimer, stopTimer]);

  useEffect(() => {
    const down = (e) => {
      if (e.repeat) return;
      if (panel) { if (e.code === "Escape") setPanel(null); return; }
      if (phase === "running") { e.preventDefault(); stopTimer(); return; }
      if (e.code === "Space") { e.preventDefault(); trigger(); }
    };
    window.addEventListener("keydown", down);
    return () => window.removeEventListener("keydown", down);
  }, [phase, trigger, stopTimer, panel]);

  useEffect(() => () => cancelAnimationFrame(raf.current), []);

  const setAgg = useMemo(() => {
    const agg = {};
    for (const st of Object.values(caseStats)) {
      const a = agg[st.set] || { n: 0, best: Infinity, sum: 0, cases: 0 };
      a.n += st.n; a.best = Math.min(a.best, st.best); a.sum += st.sum; a.cases += 1;
      agg[st.set] = a;
    }
    return agg;
  }, [caseStats]);

  const toggleSet = (id) => {
    setSelected((s) => {
      const n = new Set(s);
      if (n.has(id)) n.delete(id); else n.add(id);
      return n;
    });
  };

  const counts = useMemo(() => {
    if (!ready) return {};
    const c = {};
    for (const s of SETS) {
      const p = poolOf(s.id);
      if (p) c[s.id] = p.classes.size;
    }
    return c;
  }, [ready, poolOf]);

  const recapDone = mode === "recap" && recap && recap.idx >= recap.queue.length;

  const resetStats = () => {
    setCaseStats({});
    setSession([]);
    setLast(null);
    try { window.storage.set(STORE_KEY, JSON.stringify({ caseStats: {}, bar, selected: [...selected] })).catch(() => {}); } catch (e) {}
  };

  return (
    <div className="app">
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Chivo+Mono:wght@300;400;500&family=Instrument+Sans:wght@400;500;600&display=swap');
        :root {
          --bg: #f6f6f3; --panel: #ffffff; --panel2: #f0f1ed; --line: #e4e6e0;
          --text: #1c221e; --dim: #5d6b62; --faint: #97a29a; --accent: #1f8a4c;
        }
        * { box-sizing: border-box; }
        .app { min-height: 100vh; background: var(--bg); color: var(--text);
          font-family: 'Instrument Sans', system-ui, sans-serif;
          display: flex; flex-direction: column; align-items: center; padding: 20px 16px 40px; }
        .frame { width: 100%; max-width: 920px; }
        header { display: flex; align-items: center; gap: 14px; margin-bottom: 18px; }
        .brandrow { display: flex; align-items: center; gap: 9px; }
        .logo { width: 24px; height: 22px; color: var(--text); display: block; }
        .brand { font-weight: 600; font-size: 16px; letter-spacing: .03em; }
        .brand span { color: var(--faint); font-weight: 500; }
        .spacer { flex: 1; }
        .bar-tri { width: 58px; height: 52px; cursor: pointer; }
        .tri-fill { fill: var(--panel2); }
        .tri-edge { stroke: var(--line); stroke-width: 7; stroke-linecap: round; cursor: pointer; transition: stroke .15s; }
        .tri-edge:hover { stroke: var(--dim); }
        .tri-edge.sel { stroke: var(--accent); }
        .tri-label { fill: var(--dim); font-size: 16px; text-anchor: middle; font-family: 'Chivo Mono', monospace; pointer-events: none; }
        .gear { background: none; border: 1px solid var(--line); color: var(--dim); border-radius: 8px;
          padding: 7px 12px; cursor: pointer; font-size: 13px; font-family: inherit; }
        .gear:hover { color: var(--text); border-color: var(--dim); }
        .chips { display: flex; flex-wrap: wrap; gap: 8px; align-items: center; margin-bottom: 6px; }
        .chip { display: inline-flex; align-items: center; gap: 7px; padding: 7px 12px; border-radius: 999px;
          border: 1px solid var(--line); background: var(--panel); color: var(--dim);
          cursor: pointer; font-size: 13px; font-family: inherit; transition: all .12s; user-select: none; }
        .chip .dot { width: 8px; height: 8px; border-radius: 50%; background: var(--faint); }
        .chip .ct { color: var(--faint); font-size: 11px; font-family: 'Chivo Mono', monospace; }
        .chip.on { border-color: transparent; color: var(--text); background: #fff; box-shadow: inset 0 0 0 1.5px var(--cdot), 0 1px 2px rgba(22,30,25,.05); }
        .chip.on .dot { background: var(--cdot); }
        .grouplabel { color: var(--faint); font-size: 11px; text-transform: uppercase; letter-spacing: .1em; margin: 0 2px 0 6px; }
        .presets { display: flex; gap: 12px; margin: 4px 2px 16px; }
        .preset { background: none; border: none; color: var(--faint); font-size: 12px; cursor: pointer; padding: 0; font-family: inherit; text-decoration: underline dotted; }
        .preset:hover { color: var(--dim); }
        .modes { display: inline-flex; border: 1px solid var(--line); border-radius: 9px; overflow: hidden; margin-bottom: 14px; }
        .mode { padding: 7px 18px; background: var(--panel); border: none; color: var(--dim); cursor: pointer; font-size: 13px; font-family: inherit; }
        .mode.on { background: var(--panel2); color: var(--text); }
        .stage { background: var(--panel); border: 1px solid var(--line); border-radius: 16px; box-shadow: 0 1px 3px rgba(22,30,25,.05);
          padding: 26px 26px 24px; cursor: pointer; user-select: none; }
        .stagegrid { display: grid; grid-template-columns: 1fr; gap: 10px; align-items: center; }
        @media (min-width: 640px) { .stagegrid { grid-template-columns: 1fr 170px; } }
        .scramble { font-family: 'Chivo Mono', monospace; font-size: clamp(19px, 3vw, 27px);
          letter-spacing: .13em; line-height: 1.6; color: var(--text); text-align: left; }
        .pyranet { width: 100%; max-width: 190px; justify-self: center; }
        .timer { font-family: 'Chivo Mono', monospace; font-weight: 300; text-align: center;
          font-size: clamp(56px, 11vw, 92px); line-height: 1.1; margin: 12px 0 4px;
          color: var(--text); font-variant-numeric: tabular-nums; }
        .timer.running { color: var(--accent); }
        .hint { color: var(--faint); font-size: 13px; min-height: 1.2em; text-align: center; }
        .reveal { display: flex; justify-content: center; align-items: center; gap: 9px; font-size: 13px; color: var(--dim); }
        .reveal .tag { display: inline-flex; align-items: center; gap: 6px; padding: 3px 10px;
          border-radius: 999px; font-weight: 500; color: var(--text); background: var(--panel2);
          box-shadow: inset 0 0 0 1px var(--cdot); }
        .reveal .tag .dot { width: 7px; height: 7px; border-radius: 50%; background: var(--cdot); }
        .recapbar { display: flex; align-items: center; gap: 10px; margin: 12px 2px; color: var(--dim); font-size: 13px; }
        .rtrack { flex: 1; height: 4px; border-radius: 2px; background: var(--panel2); overflow: hidden; }
        .rfill { height: 100%; background: var(--accent); transition: width .2s; }
        .restart { background: var(--accent); color: #ffffff; border: none; border-radius: 9px;
          padding: 10px 22px; font-weight: 600; font-size: 14px; cursor: pointer; font-family: inherit; margin-top: 14px; }
        .panelrow { display: grid; grid-template-columns: 1fr; gap: 14px; margin-top: 18px; }
        @media (min-width: 700px) { .panelrow { grid-template-columns: 3fr 2fr; } }
        .card { background: var(--panel); border: 1px solid var(--line); border-radius: 14px; padding: 16px 18px; box-shadow: 0 1px 2px rgba(22,30,25,.04); }
        .card h3 { margin: 0 0 10px; font-size: 12px; font-weight: 600; color: var(--faint);
          text-transform: uppercase; letter-spacing: .1em; }
        table { width: 100%; border-collapse: collapse; font-size: 13px; }
        th { text-align: left; color: var(--faint); font-weight: 500; font-size: 11px; padding: 4px 6px; }
        td { padding: 5px 6px; border-top: 1px solid var(--line); color: var(--dim); font-variant-numeric: tabular-nums; }
        td.name { color: var(--text); }
        tr.setrow { cursor: pointer; }
        tr.setrow:hover td { color: var(--text); }
        .chev { color: var(--faint); font-size: 10px; margin-left: 8px; }
        .casegrid { display: grid; grid-template-columns: repeat(auto-fill, minmax(96px, 1fr));
          gap: 10px; margin-top: 12px; padding-top: 12px; border-top: 1px solid var(--line); }
        .casecard { background: var(--panel2); border: 1px solid var(--line); border-radius: 10px;
          padding: 8px 8px 7px; text-align: center; }
        .casecard .pyranet { max-width: 78px; }
        .casenums { display: flex; flex-direction: column; gap: 1px; margin-top: 4px; }
        .casenums .mono { font-size: 13px; color: var(--text); }
        .casesub { font-size: 10px; color: var(--faint); }
        td .dot { display: inline-block; width: 7px; height: 7px; border-radius: 50%; margin-right: 7px; }
        .mono { font-family: 'Chivo Mono', monospace; }
        .times { display: flex; flex-wrap: wrap; gap: 6px; }
        .timepill { font-family: 'Chivo Mono', monospace; font-size: 12px; padding: 3px 9px;
          border-radius: 7px; background: var(--panel2); color: var(--dim); border-left: 2px solid var(--cdot); }
        .empty { color: var(--faint); font-size: 13px; }
        .settings { background: var(--panel2); border: 1px solid var(--line); border-radius: 12px;
          padding: 14px 16px; margin-bottom: 16px; display: flex; flex-wrap: wrap; gap: 18px; align-items: center; font-size: 13px; color: var(--dim); }
        .danger { background: none; border: 1px solid #e3c0bc; color: #b04a42; border-radius: 8px; padding: 6px 12px; cursor: pointer; font-family: inherit; font-size: 12px; }
        .danger:hover { background: #faf0ee; }
        .loading { color: var(--dim); text-align: center; padding: 80px 0; font-size: 14px; }
        .casename { color: var(--text); font-weight: 500; }
        .algbtn { background: none; border: 1px solid var(--line); color: var(--dim); border-radius: 999px;
          padding: 4px 12px; cursor: pointer; font-size: 12px; font-family: inherit; }
        .algbtn:hover { color: var(--text); border-color: var(--dim); }
        .casecard.click { cursor: pointer; transition: border-color .12s; }
        .casecard.click:hover { border-color: var(--dim); }
        .overlay { position: fixed; inset: 0; background: rgba(28,34,30,.34); display: flex;
          align-items: center; justify-content: center; padding: 18px; z-index: 50; }
        .modal { background: var(--panel); border: 1px solid var(--line); border-radius: 16px;
          width: 100%; max-width: 580px; max-height: 84vh; overflow-y: auto; padding: 20px 22px;
          box-shadow: 0 12px 40px rgba(22,30,25,.18); cursor: default; }
        .modalhead { display: flex; align-items: flex-start; justify-content: space-between; gap: 12px; margin-bottom: 12px; }
        .modaltitle { font-size: 18px; font-weight: 600; margin-bottom: 7px; }
        .modal .tag { display: inline-flex; align-items: center; gap: 6px; padding: 3px 10px; font-size: 12px;
          border-radius: 999px; font-weight: 500; color: var(--text); background: var(--panel2);
          box-shadow: inset 0 0 0 1px var(--cdot); }
        .modal .tag .dot { width: 7px; height: 7px; border-radius: 50%; background: var(--cdot); }
        .closebtn { background: none; border: none; color: var(--faint); font-size: 22px; cursor: pointer;
          line-height: 1; padding: 2px 6px; font-family: inherit; }
        .closebtn:hover { color: var(--text); }
        .panelimg { display: flex; justify-content: center; margin: 6px 0 14px; }
        .panelimg .pyranet { max-width: 150px; }
        .panelimg.small { margin: 0; }
        .panelimg.small .pyranet { max-width: 92px; }
        .alggroup { margin-bottom: 14px; }
        .grouphead { font-size: 11px; text-transform: uppercase; letter-spacing: .09em; color: var(--faint);
          font-weight: 600; margin-bottom: 6px; }
        .bartag { text-transform: none; letter-spacing: 0; font-weight: 500; color: var(--dim); margin-left: 6px; }
        .alglist { display: flex; flex-direction: column; gap: 4px; }
        .algrow { display: flex; align-items: baseline; justify-content: space-between; gap: 12px;
          padding: 6px 10px; background: var(--panel2); border-radius: 8px; }
        .algrow .alg { font-size: 13.5px; color: var(--text); letter-spacing: .04em; }
        .algrow .algname { font-size: 11px; color: var(--faint); white-space: nowrap; }
        .presrow { display: flex; gap: 14px; align-items: flex-start; padding-top: 12px; border-top: 1px solid var(--line); }
        .presbody { flex: 1; }
        @media (prefers-reduced-motion: reduce) { * { transition: none !important; } }
      `}</style>

      <div className="frame">
        <header>
          <div className="brandrow">
            <svg className="logo" viewBox="0 0 40 36" aria-hidden="true">
              <polygon points="20,2 2,34 38,34" fill="none" stroke="currentColor" strokeWidth="2.6" strokeLinejoin="round" />
              <polygon points="20,14.8 11,30.4 29,30.4" fill="var(--accent)" stroke="none" />
            </svg>
            <div className="brand">L5E <span>Trainer</span></div>
          </div>
          <div className="spacer" />
          <BarTriangle bar={bar} onPick={setBar} />
          <button className="gear" onClick={() => setSettingsOpen((o) => !o)}>Settings</button>
        </header>

        {settingsOpen && (
          <div className="settings">
            <span>Stats persist between sessions.</span>
            <button className="danger" onClick={resetStats}>Reset all stats</button>
          </div>
        )}

        <div className="chips">
          <span className="grouplabel" style={{ marginLeft: 0 }}>L5E</span>
          {SETS.filter((s) => s.group === "L5E").map((s) => (
            <button key={s.id} className={"chip" + (selected.has(s.id) ? " on" : "")}
              style={{ "--cdot": s.color }} onClick={() => toggleSet(s.id)}>
              <span className="dot" />{s.name}
              {ready && <span className="ct">{counts[s.id]}</span>}
            </button>
          ))}
          <span className="grouplabel">L4E</span>
          {SETS.filter((s) => s.group === "L4E").map((s) => (
            <button key={s.id} className={"chip" + (selected.has(s.id) ? " on" : "")}
              style={{ "--cdot": s.color }} onClick={() => toggleSet(s.id)}>
              <span className="dot" />{s.name}
              {ready && <span className="ct">{counts[s.id]}</span>}
            </button>
          ))}
        </div>
        <div className="presets">
          <button className="preset" onClick={() => setSelected(new Set(L5E_IDS))}>all L5E</button>
          <button className="preset" onClick={() => setSelected(new Set(ALL_IDS))}>everything</button>
          <button className="preset" onClick={() => setSelected(new Set())}>none</button>
        </div>

        <div className="modes">
          <button className={"mode" + (mode === "drill" ? " on" : "")} onClick={() => setMode("drill")}>Drill</button>
          <button className={"mode" + (mode === "recap" ? " on" : "")} onClick={() => setMode("recap")}>Recap</button>
        </div>

        {mode === "recap" && recap && recap.queue.length > 0 && (
          <div className="recapbar">
            <span className="mono">{Math.min(recap.idx, recap.queue.length)}/{recap.queue.length}</span>
            <div className="rtrack"><div className="rfill" style={{ width: `${(Math.min(recap.idx, recap.queue.length) / recap.queue.length) * 100}%` }} /></div>
            <button className="preset" onClick={startRecap}>restart</button>
          </div>
        )}

        {!ready ? (
          <div className="stage" style={{ cursor: "default" }}><div className="loading">Building scramble tables…</div></div>
        ) : recapDone ? (
          <div className="stage" style={{ cursor: "default", textAlign: "center" }}>
            <div className="scramble" style={{ textAlign: "center" }}>Recap complete</div>
            <div className="hint" style={{ marginTop: 10 }}>{recap.queue.length} cases covered</div>
            <button className="restart" onClick={startRecap}>Run it again</button>
          </div>
        ) : !current ? (
          <div className="stage" style={{ cursor: "default" }}>
            <div className="empty" style={{ padding: "40px 0", textAlign: "center" }}>Select at least one set to start.</div>
          </div>
        ) : (
          <div className="stage" onPointerDown={(e) => { e.preventDefault(); trigger(); }}>
            <div className="stagegrid">
              <div className="scramble">{current.scramble || "—"}</div>
              <PyraminxNet state={current.render} uTwist={current.uTwist} />
            </div>
            <div className={"timer" + (phase === "running" ? " running" : "")}>{fmt(elapsed)}</div>
            {phase === "stopped" && last ? (
              <div className="reveal">
                <span>that was</span>
                <span className="tag" style={{ "--cdot": SET_BY_ID[last.set].color }}>
                  <span className="dot" />{SET_BY_ID[last.set].name}
                </span>
                {lookupName(last.render, last.uTwist, last.caseKey) ? (
                  <span className="casename">{lookupName(last.render, last.uTwist, last.caseKey)}</span>
                ) : null}
                <button className="algbtn" onPointerDown={(e) => e.stopPropagation()}
                  onClick={(e) => { e.stopPropagation(); setPanel({ kind: "live", ...last }); }}>
                  view algs
                </button>
              </div>
            ) : (
              <div className="hint">{phase === "running" ? "tap or any key to stop" : "tap or space to start"}</div>
            )}
          </div>
        )}

        <div className="panelrow">
          <div className="card">
            <h3>Stats by set</h3>
            {Object.keys(setAgg).length === 0 ? (
              <div className="empty">No solves yet. Times land here, grouped by set.</div>
            ) : (
              <table>
                <thead><tr><th>Set</th><th>Solves</th><th>Cases seen</th><th>Best</th><th>Mean</th></tr></thead>
                <tbody>
                  {SETS.filter((s) => setAgg[s.id]).map((s) => {
                    const a = setAgg[s.id];
                    return (
                      <tr key={s.id} className="setrow" onClick={() => setExpandedSet(expandedSet === s.id ? null : s.id)}>
                        <td className="name">
                          <span className="dot" style={{ background: s.color }} />{s.name}
                          <span className="chev">{expandedSet === s.id ? "▾" : "▸"}</span>
                        </td>
                        <td className="mono">{a.n}</td>
                        <td className="mono">{a.cases}{counts[s.id] ? ` / ${counts[s.id]}` : ""}</td>
                        <td className="mono">{fmt(a.best)}</td>
                        <td className="mono">{fmt(a.sum / a.n)}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            )}
            {expandedSet && setAgg[expandedSet] && (
              <div className="casegrid">
                {Object.entries(caseStats)
                  .filter(([, st]) => st.set === expandedSet)
                  .sort((a, b) => b[1].sum / b[1].n - a[1].sum / a[1].n)
                  .map(([ck, st]) => (
                    <div key={ck} className="casecard click" onClick={() => setPanel({ kind: "class", caseKey: ck, set: st.set })}>
                      <PyraminxNet state={displayState(ck, st.set, bar)} uTwist={+ck.split("|")[1]} />
                      <div className="casenums">
                        <span className="mono">{fmt(st.sum / st.n)}</span>
                        <span className="casesub">{SHEET.CNAME[ck] || "unnamed"}</span>
                        <span className="casesub">best {fmt(st.best)} · {st.n}×</span>
                      </div>
                    </div>
                  ))}
              </div>
            )}
          </div>
          <div className="card">
            <h3>Session</h3>
            {session.length === 0 ? (
              <div className="empty">Recent times show up here.</div>
            ) : (
              <div className="times">
                {session.slice(-24).map((t, i) => (
                  <span key={i} className="timepill" style={{ "--cdot": SET_BY_ID[t.set].color }}>{fmt(t.ms)}</span>
                ))}
              </div>
            )}
          </div>
        </div>
        {panel && <AlgPanel panel={panel} onClose={() => setPanel(null)} />}
      </div>
    </div>
  );
}
